// ── Parse & Validate Retell Payload ──────────────────────────────────────
const body = $input.first().json.body || $input.first().json;
const call = body.call || body;

// Core call metadata
const callId        = call.call_id         || '';
const callStatus    = call.call_status     || 'unknown';
const recordingUrl  = call.recording_url   || '';
const callDuration  = call.duration_ms     || call.call_duration || 0;
const callStartTime = call.start_timestamp || '';
const callEndTime   = call.end_timestamp   || '';
const fromNumber    = call.from_number     || call.to_number || '';

// Post Call Analysis data (if available)
const vars         = call.call_analysis?.custom_analysis_data || call.custom_data || {};
const postCallData = call.call_analysis || {};

const intentBucket    = postCallData.intent_bucket    || '';
const productBucket   = postCallData.product_bucket   || '';
const transferOutcome = postCallData.transfer_outcome || '';
const callSummary     = postCallData.call_summary     || '';
const crmHandoffNote  = postCallData.crm_handoff_note || '';
const userSentiment   = postCallData.user_sentiment   || '';

// ✅ Tool call arguments থেকে data নিন (trigger_callback_workflow)
const toolCallArgs = (() => {
  try {
    const tc = call.tool_calls?.find(t => t.name === 'trigger_callback_workflow');
    return tc ? JSON.parse(tc.arguments || '{}') : {};
  } catch { return {}; }
})();

// ✅ transcript_with_tool_calls থেকেও চেক করুন
const toolCallArgsFromTranscript = (() => {
  try {
    const tc = call.transcript_with_tool_calls?.find(
      t => t.role === 'tool_call_invocation' && t.name === 'trigger_callback_workflow'
    );
    return tc ? JSON.parse(tc.arguments || '{}') : {};
  } catch { return {}; }
})();

// Merge করুন — transcript > tool_calls > call_analysis
const merged = { ...toolCallArgs, ...toolCallArgsFromTranscript };

// Caller fields — both naming conventions supported
const callerName      = (vars.caller_first_name       || vars.caller_name         || merged.first_name        || '').trim();
const callerPhone     = (vars.caller_phone_collected  || vars.caller_phone        || fromNumber               || '').trim();
const callerState     = (vars.caller_state            || merged.caller_state      || '').trim();
const productInterest = (vars.caller_product_interest || vars.product_interest    || merged.reason            || '').trim();
const urgency         = (vars.caller_urgency          || vars.urgency             || merged.urgency           || '').trim();
const callOutcome     = (vars.call_outcome            || merged.call_outcome      || 'unknown').trim().toLowerCase();
const appointmentSet  = vars.appointment_set === true || vars.appointment_set === 'true';
const afterHours      = vars.after_hours     === true || vars.after_hours     === 'true';
const callerMessage   = (merged.reason || vars.caller_message || '').trim();

// ── Phone format (E.164) ──────────────────────────────────────────────────
const digits = callerPhone.replace(/\D/g, '');
const callerPhoneFormatted = callerPhone.startsWith('+')
  ? callerPhone
  : digits.length === 10
    ? '+1' + digits
    : digits.length === 11 && digits.startsWith('1')
      ? '+' + digits
      : callerPhone;

// ── Validation ────────────────────────────────────────────────────────────
const missingFields = [];
if (!callerPhoneFormatted || callerPhoneFormatted === '+1') missingFields.push('phone');
if (!callerName) missingFields.push('name');

const isValid = missingFields.length === 0;

// ── Qualification logic ───────────────────────────────────────────────────
const disqualifiedOutcomes = ['disqualified', 'wrong_number', 'spam', 'hangup'];
const isQualified = isValid
  && productInterest !== ''
  && !disqualifiedOutcomes.includes(callOutcome);

return [{
  json: {
    callId, callStatus, recordingUrl, callDuration, callStartTime, callEndTime,
    callerName, callerPhone: callerPhoneFormatted, callerState,
    productInterest, urgency, callOutcome, appointmentSet, afterHours, callerMessage,
    intentBucket, productBucket, transferOutcome, callSummary, crmHandoffNote, userSentiment,
    isValid, isQualified, missingFields,
    ghlTag: isQualified ? 'Qualified Lead' : 'Disqualified',
    leadSource: 'Ava Inbound Call'
  }
}];

// Log invalid/incomplete payloads for manual review
const data = $input.first().json;
console.error('Invalid Retell payload received', JSON.stringify({
  callId: data.callId,
  missingFields: data.missingFields,
  timestamp: new Date().toISOString()
}));
return [{ json: { error: true, reason: 'Missing required fields', missingFields: data.missingFields } }];

